184→                .with_tonic()
185→                .with_endpoint(endpoint);
186→
187→            if !config.otlp_headers.is_empty() {
188→                let mut metadata = tonic::metadata::MetadataMap::new();
189→                for (key, value) in &config.otlp_headers {
190→                    if let (Ok(k), Ok(v)) = (
191→                        key.parse::<tonic::metadata::MetadataKey<tonic::metadata::Ascii>>(),
192→                        value.parse::<tonic::metadata::MetadataValue<tonic::metadata::Ascii>>(),
193→                    ) {
194→                        metadata.insert(k, v);
195→                    }
196→                }
197→                builder = builder.with_metadata(metadata);
198→            }
199→
200→            builder
201→                .build()
202→                .map_err(|e| VigError::SpanExporter(e.to_string()))?
203→        }
204→        OtlpProtocol::Http => opentelemetry_otlp::SpanExporter::builder()
205→            .with_http()
206→            .with_endpoint(endpoint)
207→            .build()
208→            .map_err(|e| VigError::SpanExporter(e.to_string()))?,
209→    };
210→
211→    let provider = SdkTracerProvider::builder()
212→        .with_batch_exporter(exporter)
213→        .with_resource(resource)
214→        .build();
215→
216→    Ok(provider)
