  1→//! Contract-derived span builders for the Life Agent OS.
  2→//!
  3→//! Provides helper functions that create properly-attributed `tracing` spans
  4→//! from aiOS kernel types. The `tracing-opentelemetry` layer bridges these
  5→//! to OTel spans automatically.
  6→
  7→use aios_protocol::event::{EventEnvelope, LoopPhase, TokenUsage};
  8→use tracing::Span;
  9→
 10→use crate::semconv;
 11→
 12→/// Create a root `invoke_agent` span for an agent session.
 13→///
 14→/// This is the top-level span for an agent invocation, containing all
 15→/// loop phases and LLM calls as children.
 16→pub fn agent_span(session_id: &str, agent_name: &str) -> Span {
 17→    tracing::info_span!(
 18→        "invoke_agent",
 19→        { semconv::GEN_AI_OPERATION_NAME } = "invoke_agent",
 20→        { semconv::GEN_AI_AGENT_NAME } = agent_name,
 21→        { semconv::GEN_AI_AGENT_ID } = session_id,
 22→        { semconv::LIFE_SESSION_ID } = session_id,
 23→    )
 24→}
 25→
 26→/// Create a child span for a loop phase.
 27→pub fn phase_span(phase: LoopPhase) -> Span {
 28→    let phase_str = match phase {
 29→        LoopPhase::Perceive => "perceive",
 30→        LoopPhase::Deliberate => "deliberate",
 31→        LoopPhase::Gate => "gate",
 32→        LoopPhase::Execute => "execute",
 33→        LoopPhase::Commit => "commit",
 34→        LoopPhase::Reflect => "reflect",
 35→        LoopPhase::Sleep => "sleep",
 36→    };
 37→
 38→    tracing::info_span!("loop_phase", { semconv::LIFE_LOOP_PHASE } = phase_str,)
 39→}
 40→
 41→/// Create a GenAI `chat` client span for an LLM call.
 42→///
 43→/// Follows the OTel GenAI semantic convention for client spans:
 44→/// `chat {gen_ai.request.model}` naming pattern.
 45→pub fn chat_span(
 46→    model: &str,
 47→    provider: &str,
 48→    max_tokens: Option<u32>,
 49→    temperature: Option<f64>,
 50→) -> Span {
 51→    tracing::info_span!(
 52→        "chat",
 53→        { semconv::GEN_AI_OPERATION_NAME } = "chat",
 54→        { semconv::GEN_AI_SYSTEM } = provider,
 55→        { semconv::GEN_AI_REQUEST_MODEL } = model,
 56→        { semconv::GEN_AI_REQUEST_MAX_TOKENS } = max_tokens,
 57→        { semconv::GEN_AI_REQUEST_TEMPERATURE } = temperature,
 58→        // These will be filled in after the response:
 59→        { semconv::GEN_AI_USAGE_INPUT_TOKENS } = tracing::field::Empty,
 60→        { semconv::GEN_AI_USAGE_OUTPUT_TOKENS } = tracing::field::Empty,
 61→        { semconv::GEN_AI_RESPONSE_FINISH_REASONS } = tracing::field::Empty,
 62→        { semconv::GEN_AI_RESPONSE_ID } = tracing::field::Empty,
 63→    )
 64→}
 65→
 66→/// Create a GenAI `execute_tool` span for a tool call.
 67→pub fn tool_span(tool_name: &str, tool_call_id: &str) -> Span {
 68→    tracing::info_span!(
 69→        "execute_tool",
 70→        { semconv::GEN_AI_OPERATION_NAME } = "execute_tool",
 71→        { semconv::GEN_AI_TOOL_NAME } = tool_name,
 72→        { semconv::GEN_AI_TOOL_CALL_ID } = tool_call_id,
 73→        { semconv::LIFE_TOOL_STATUS } = tracing::field::Empty,
 74→    )
 75→}
 76→
 77→/// Record token usage on the current span.
 78→///
 79→/// Sets `gen_ai.usage.input_tokens` and `gen_ai.usage.output_tokens`.
 80→pub fn record_token_usage(span: &Span, usage: &TokenUsage) {
