 176→async fn shutdown_signal() {
 177→    let ctrl_c = tokio::signal::ctrl_c();
 178→
 179→    #[cfg(unix)]
 180→    {
 181→        let mut sigterm = tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
 182→            .expect("failed to install SIGTERM handler");
 183→        tokio::select! {
 184→            _ = ctrl_c => {},
 185→            _ = sigterm.recv() => {},
 186→        }
 187→    }
 188→
 189→    #[cfg(not(unix))]
 190→    {
 191→        ctrl_c.await.ok();
 192→    }
 193→
 194→    tracing::info!("Received shutdown signal, draining connections...");
 195→}
