 197→fn resolve_data_dir(data_dir: &PathBuf) -> anyhow::Result<PathBuf> {
 198→    let workspace_root = std::env::current_dir()?;
 199→    Ok(if data_dir.is_relative() {
 200→        workspace_root.join(data_dir)
 201→    } else {
 202→        data_dir.clone()
 203→    })
 204→}
