 206→fn read_last_session_hint(data_dir: &Path) -> Option<String> {
 207→    let path = data_dir.join("last_session");
 208→    let raw = std::fs::read_to_string(path).ok()?;
 209→    let session = raw.trim();
 210→    if session.is_empty() {
 211→        None
 212→    } else {
 213→        Some(session.to_owned())
 214→    }
 215→}
 216→
 217→fn persist_last_session_hint(data_dir: &Path, session: &str) -> anyhow::Result<()> {
 218→    std::fs::create_dir_all(data_dir)?;
 219→    std::fs::write(data_dir.join("last_session"), session)?;
 220→    Ok(())
 221→}
