 223→/// Resolve session via the daemon's HTTP API first, falling back to local hints.
 224→/// This avoids opening the journal (which would conflict with the daemon's redb lock).
 225→async fn resolve_session(
 226→    data_dir: &Path,
 227→    requested: Option<String>,
 228→    base_url: Option<&str>,
 229→) -> String {
 230→    if let Some(session) = requested {
 231→        return session;
 232→    }
 233→
 234→    if let Some(session) = read_last_session_hint(data_dir) {
 235→        return session;
 236→    }
 237→
 238→    // Try the HTTP API if a daemon URL is available (avoids redb lock conflict).
 239→    if let Some(url) = base_url {
 240→        if let Some(session) = cli_run::resolve_session_via_api(url).await {
 241→            return session;
 242→        }
 243→    }
 244→
 245→    "default".to_owned()
 246→}
 247→
 248→/// Try to create an OpenAI provider from stored OAuth credentials.
 249→fn try_openai_oauth_provider() -> Option<Arc<dyn Provider>> {
 250→    let tokens = arcan_provider::oauth::load_tokens("openai").ok()?;
 251→    let credential = Arc::new(arcan_provider::oauth::OAuthCredential::openai(tokens));
 252→    let model = std::env::var("OPENAI_MODEL").unwrap_or_else(|_| "gpt-4o".to_string());
 253→    let config = arcan_provider::openai::OpenAiConfig::from_oauth(credential, model.clone());
 254→    tracing::info!(%model, "Provider: OpenAI (OAuth)");
 255→    Some(Arc::new(
 256→        arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 257→    ))
 258→}
 259→
 260→/// Build provider from resolved configuration.
 261→fn build_provider(resolved: &ResolvedConfig) -> anyhow::Result<Arc<dyn Provider>> {
 262→    let pc = resolved.provider_config.as_ref();
 263→
 264→    match resolved.provider.as_str() {
 265→        "mock" => {
 266→            tracing::warn!("Provider: MockProvider (forced via config)");
 267→            Ok(Arc::new(MockProvider))
 268→        }
 269→        "openai" | "codex" | "openai-codex" => {
 270→            // Try OAuth credential first, then fall back to env var / resolved config.
 271→            if let Some(p) = try_openai_oauth_provider() {
 272→                return Ok(p);
 273→            }
 274→            let config = arcan_provider::openai::OpenAiConfig::openai_from_resolved(
 275→                resolved.model.as_deref(),
 276→                pc.and_then(|p| p.base_url.as_deref()),
 277→                pc.and_then(|p| p.max_tokens),
 278→            )?;
 279→            tracing::info!(model = %config.model, "Provider: OpenAI");
 280→            Ok(Arc::new(
 281→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 282→            ))
 283→        }
 284→        "ollama" => {
 285→            let config = arcan_provider::openai::OpenAiConfig::ollama_from_resolved(
 286→                resolved.model.as_deref(),
 287→                pc.and_then(|p| p.base_url.as_deref()),
 288→                pc.and_then(|p| p.max_tokens),
 289→                pc.and_then(|p| p.enable_streaming),
 290→            )?;
 291→            tracing::info!(model = %config.model, base_url = %config.base_url, "Provider: Ollama");
 292→            Ok(Arc::new(
 293→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 294→            ))
 295→        }
 296→        "anthropic" => {
 297→            let config = AnthropicConfig::from_resolved(
 298→                resolved.model.as_deref(),
 299→                pc.and_then(|p| p.base_url.as_deref()),
 300→                pc.and_then(|p| p.max_tokens),
 301→            )?;
 302→            tracing::info!(model = %config.model, "Provider: Anthropic");
 303→            Ok(Arc::new(AnthropicProvider::new(config)))
 304→        }
 305→        // Auto-detect: try providers in order
 306→        _ => {
 307→            if let Ok(config) = AnthropicConfig::from_env() {
 308→                tracing::info!(model = %config.model, "Provider: Anthropic (auto-detected)");
 309→                Ok(Arc::new(AnthropicProvider::new(config)))
 310→            } else if let Some(p) = try_openai_oauth_provider() {
 311→                Ok(p)
 312→            } else if let Ok(config) = arcan_provider::openai::OpenAiConfig::openai_from_env() {
 313→                tracing::info!(model = %config.model, "Provider: OpenAI (auto-detected)");
 314→                Ok(Arc::new(
 315→                    arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 316→                ))
 317→            } else {
 318→                tracing::warn!(
 319→                    "Provider: MockProvider (set ARCAN_PROVIDER or API key env vars for real LLM)"
 320→                );
 321→                Ok(Arc::new(MockProvider))
 322→            }
 323→        }
 324→    }
 325→}
