 327→fn run_serve(
 328→    data_dir: &Path,
 329→    resolved: &ResolvedConfig,
 330→    console_dir: Option<PathBuf>,
 331→) -> anyhow::Result<()> {
 332→    let workspace_root = std::env::current_dir()?;
 333→
 334→    // --- Lago persistence ---
 335→    let journal_path = data_dir.join("journal.redb");
 336→    let blobs_path = data_dir.join("blobs");
 337→    std::fs::create_dir_all(&blobs_path)?;
 338→
 339→    tracing::info!(
 340→        workspace = %workspace_root.display(),
 341→        journal = %journal_path.display(),
 342→        blobs = %blobs_path.display(),
 343→        provider = %resolved.provider,
 344→        model = ?resolved.model,
 345→        port = resolved.port,
 346→        "Starting arcan"
 347→    );
 348→
 349→    let journal = RedbJournal::open(&journal_path)?;
 350→    let blob_store = Arc::new(lago_store::BlobStore::open(&blobs_path)?);
 351→    let journal: Arc<dyn lago_core::Journal> = Arc::new(journal);
 352→
 353→    // --- Lago-tracked filesystem (O(1) write tracking via FsTracker) ---
 354→    let fs_policy = FsPolicy::new(workspace_root.clone());
 355→    let local_fs = LocalFs::new(fs_policy);
 356→    let tracker = Arc::new(FsTracker::new(Manifest::new(), blob_store.clone()));
 357→    let (fs_event_tx, fs_event_rx) = tokio::sync::mpsc::channel(1000);
 358→    let tracked_fs: Arc<dyn FsPort> = Arc::new(LagoTrackedFs::new(local_fs, tracker, fs_event_tx));
 359→
 360→    let sandbox_policy = SandboxPolicy {
 361→        workspace_root: workspace_root.clone(),
 362→        shell_enabled: true,
 363→        network: NetworkPolicy::AllowAll,
 364→        allowed_env: BTreeSet::new(),
 365→        max_execution_ms: 10_000,
 366→        max_stdout_bytes: 1024 * 1024,
 367→        max_stderr_bytes: 1024 * 1024,
 368→    };
 369→
 370→    // --- Tools (Praxis canonical implementations, bridged into Arcan) ---
 371→    let mut registry = ToolRegistry::default();
 372→    registry.register(PraxisToolBridge::new(ReadFileTool::new(tracked_fs.clone())));
 373→    registry.register(PraxisToolBridge::new(WriteFileTool::new(
 374→        tracked_fs.clone(),
 375→    )));
 376→    registry.register(PraxisToolBridge::new(ListDirTool::new(tracked_fs.clone())));
 377→    registry.register(PraxisToolBridge::new(EditFileTool::new(tracked_fs.clone())));
 378→    registry.register(PraxisToolBridge::new(GlobTool::new(tracked_fs.clone())));
 379→    registry.register(PraxisToolBridge::new(GrepTool::new(tracked_fs)));
 380→
 381→    let runner = Box::new(LocalCommandRunner);
 382→    registry.register(PraxisToolBridge::new(BashTool::new(sandbox_policy, runner)));
 383→
 384→    let memory_dir = data_dir.join("memory");
 385→    std::fs::create_dir_all(&memory_dir)?;
 386→    registry.register(PraxisToolBridge::new(ReadMemoryTool::new(
 387→        memory_dir.clone(),
 388→    )));
 389→    registry.register(PraxisToolBridge::new(WriteMemoryTool::new(memory_dir)));
 390→
 391→    // --- Governed memory tools (event-sourced via Lago) ---
 392→    let memory_projection = Arc::new(RwLock::new(MemoryProjection::new()));
 393→    registry.register(MemoryQueryTool::new(memory_projection));
 394→    registry.register(MemoryProposeTool::new(journal.clone()));
 395→    registry.register(MemoryCommitTool::new(journal.clone()));
 396→
 397→    // --- Spaces distributed networking (opt-in) ---
 398→    #[cfg(feature = "spaces")]
 399→    {
 400→        let spaces_port: Arc<dyn arcan_spaces::SpacesPort> = match resolved.spaces_backend.as_str()
 401→        {
 402→            "spacetimedb" | "mainnet" => {
 403→                let stdb_config = arcan_spaces::SpacetimeDbConfig::resolve(
 404→                    resolved.spaces_host.as_deref(),
 405→                    resolved.spaces_database_id.as_deref(),
 406→                    resolved.spaces_token.as_deref(),
 407→                )
 408→                .map_err(|e| anyhow::anyhow!("spaces config: {e}"))?;
 409→                tracing::info!(
 410→                    host = %stdb_config.host,
 411→                    database = %stdb_config.database_id,
 412→                    "Spaces: SpacetimeDB backend"
 413→                );
 414→                Arc::new(arcan_spaces::SpacetimeDbClient::new(stdb_config))
 415→            }
 416→            _ => {
 417→                tracing::info!("Spaces: mock backend");
 418→                Arc::new(arcan_spaces::MockSpacesClient::default_hub())
 419→            }
 420→        };
 421→        arcan_spaces::register_spaces_tools(&mut registry, spaces_port);
 422→    }
 423→
 424→    // --- Provider ---
 425→    let provider = build_provider(resolved)?;
 426→
 427→    // Swappable handle for live provider switching
 428→    let provider_handle: arcan_core::runtime::SwappableProviderHandle =
 429→        Arc::new(std::sync::RwLock::new(provider));
 430→    let provider_factory: Arc<dyn arcan_core::runtime::ProviderFactory> =
 431→        Arc::new(factory::ArcanProviderFactory);
 432→
 433→    // --- Canonical aiOS runtime adapters ---
 434→    let event_store: Arc<dyn EventStorePort> =
 435→        Arc::new(LagoAiosEventStoreAdapter::new(journal.clone()));
 436→    let base_policy: Arc<dyn PolicyGatePort> =
 437→        Arc::new(ArcanPolicyAdapter::new(aios_protocol::PolicySet::default()));
 438→
 439→    // --- Autonomic advisory gate (embedded by default, remote via --autonomic-url) ---
 440→    let (policy_gate, economic_handle): (Arc<dyn PolicyGatePort>, EconomicGateHandle) =
 441→        if let Some(url) = &resolved.autonomic_url {
 442→            // Remote: consult standalone Autonomic daemon via HTTP.
 443→            tracing::info!(url = %url, "Autonomic advisory enabled (remote)");
 444→            let adapter = AutonomicPolicyAdapter::new_remote(base_policy, url.clone());
 445→            let handle = adapter.economic_handle();
 446→            (Arc::new(adapter), handle)
 447→        } else {
 448→            // Embedded: run controller in-process (default).
 449→            tracing::info!("Autonomic advisory enabled (embedded)");
 450→            let adapter = AutonomicPolicyAdapter::new_embedded(base_policy);
 451→            let handle = adapter.economic_handle();
 452→            (Arc::new(adapter), handle)
 453→        };
 454→
 455→    // --- Provider adapter (wired with economic handle for cost gating) ---
 456→    // Shared handle: starts empty, filled after runtime creation.
 457→    let streaming_sender: StreamingSenderHandle = Arc::new(std::sync::Mutex::new(None));
 458→    let tool_definitions = registry.definitions();
 459→    let provider_adapter: Arc<dyn ModelProviderPort> = Arc::new(
 460→        ArcanProviderAdapter::from_handle(
 461→            provider_handle.clone(),
 462→            tool_definitions,
 463→            streaming_sender.clone(),
 464→        )
 465→        .with_economic_handle(economic_handle),
 466→    );
 467→    let tool_harness: Arc<dyn ToolHarnessPort> = Arc::new(ArcanHarnessAdapter::new(registry));
 468→
 469→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ArcanApprovalAdapter::new());
 470→
 471→    let runtime = Arc::new(KernelRuntime::new(
 472→        RuntimeConfig::new(data_dir.to_path_buf()),
 473→        event_store,
 474→        provider_adapter,
 475→        tool_harness,
 476→        approvals,
 477→        policy_gate,
 478→    ));
 479→
 480→    // Wire the broadcast sender now that the runtime exists.
 481→    *streaming_sender.lock().unwrap() = Some(runtime.event_sender());
 482→
 483→    // Build provider stack and blocking HTTP clients before entering Tokio runtime.
 484→    let data_dir_owned = data_dir.to_path_buf();
 485→    let port = resolved.port;
 486→    let tokio_runtime = tokio::runtime::Builder::new_multi_thread()
 487→        .enable_all()
 488→        .build()?;
 489→
 490→    tokio_runtime.block_on(async move {
 491→        // --- Background FS event writer (persists tracked writes to Lago journal) ---
 492→        let session_id = SessionId::from_string("default");
 493→        let branch_id = BranchId::from_string("main");
 494→        tokio::spawn(run_event_writer(
 495→            fs_event_rx,
 496→            journal,
 497→            session_id,
 498→            branch_id,
 499→        ));
 500→
 501→        // --- HTTP Server ---
 502→        let mut router = create_canonical_router(runtime, provider_handle, provider_factory);
 503→
 504→        // --- Console UI ---
 505→        #[cfg(feature = "console")]
 506→        {
 507→            let console_config = arcan_console::ConsoleConfig {
 508→                override_dir: console_dir,
 509→            };
 510→            router = router.nest("/console", arcan_console::console_router(console_config));
 511→        }
 512→
 513→        // --- CORS (for dev mode with separate Vite server) ---
 514→        let cors = tower_http::cors::CorsLayer::permissive();
 515→        let router = router.layer(cors);
 516→
 517→        let addr = std::net::SocketAddr::from(([127, 0, 0, 1], port));
 518→        let listener = TcpListener::bind(addr).await?;
 519→
 520→        tracing::info!(%addr, "Listening");
 521→        axum::serve(listener, router)
 522→            .with_graceful_shutdown(shutdown_signal())
 523→            .await?;
 524→
 525→        // Clean up PID file on graceful shutdown.
 526→        daemon::remove_pid_file(&data_dir_owned);
 527→
 528→        tracing::info!("Server shut down gracefully");
 529→        Ok(())
 530→    })
 531→}
