 533→async fn run_chat(
 534→    data_dir: PathBuf,
 535→    resolved: &ResolvedConfig,
 536→    session: Option<String>,
 537→    url: Option<String>,
 538→) -> anyhow::Result<()> {
 539→    // Ensure daemon is running first to avoid redb lock conflicts.
 540→    let base_url = match url {
 541→        Some(u) => u,
 542→        None => {
 543→            daemon::ensure_daemon(
 544→                &data_dir,
 545→                resolved.port,
 546→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 547→                resolved.model.as_deref(),
 548→            )
 549→            .await?
 550→        }
 551→    };
 552→
 553→    // Resolve session via API (no direct journal access).
 554→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 555→    tracing::info!(session = %session, "launching TUI");
 556→
 557→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 558→        tracing::warn!(%error, "failed to persist last_session hint");
 559→    }
 560→
 561→    arcan_tui::run_tui(base_url, session).await
 562→}
