 608→fn run_config(data_dir: &Path, action: ConfigAction) -> anyhow::Result<()> {
 609→    match action {
 610→        ConfigAction::Init => {
 611→            let path = config::local_config_path(data_dir);
 612→            if path.exists() {
 613→                println!("Config file already exists: {}", path.display());
 614→            } else {
 615→                std::fs::create_dir_all(data_dir)?;
 616→                std::fs::write(&path, config::default_config_content())?;
 617→                println!("Created config: {}", path.display());
 618→            }
 619→        }
 620→        ConfigAction::Set { key, value } => {
 621→            let mut cfg = config::load_config(data_dir);
 622→            cfg.set_key(&key, &value)
 623→                .map_err(|e| anyhow::anyhow!("{e}"))?;
 624→            config::save_config(data_dir, &cfg)?;
 625→            println!("{key} = {value}");
 626→        }
 627→        ConfigAction::Get { key } => {
 628→            let cfg = config::load_config(data_dir);
 629→            match cfg.get_key(&key) {
 630→                Some(value) => println!("{value}"),
 631→                None => println!("(not set)"),
 632→            }
 633→        }
 634→        ConfigAction::List => {
 635→            let cfg = config::load_config(data_dir);
 636→            let content = toml::to_string_pretty(&cfg)
 637→                .map_err(|e| anyhow::anyhow!("failed to serialize config: {e}"))?;
 638→            if content.trim().is_empty()
 639→                || content.trim() == "[defaults]\n\n[agent]"
 640→                || content
 641→                    .lines()
 642→                    .all(|l| l.trim().is_empty() || l.starts_with('['))
 643→            {
 644→                println!("(no config values set)");
 645→                if let Some(path) = config::global_config_path() {
 646→                    println!("Global config: {}", path.display());
 647→                }
 648→                println!(
 649→                    "Local config:  {}",
 650→                    config::local_config_path(data_dir).display()
 651→                );
 652→            } else {
 653→                print!("{content}");
 654→            }
 655→        }
 656→    }
 657→    Ok(())
 658→}
