 730→fn run_login(provider: &str, device: bool, data_dir: &Path) -> anyhow::Result<()> {
 731→    // Normalize to canonical provider name for config persistence.
 732→    let canonical = match provider {
 733→        "codex" | "openai-codex" => "openai",
 734→        other => other,
 735→    };
 736→
 737→    match provider {
 738→        "openai" | "codex" | "openai-codex" => {
 739→            if device {
 740→                arcan_provider::oauth::device_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 741→            } else {
 742→                arcan_provider::oauth::pkce_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 743→            }
 744→        }
 745→        _ => {
 746→            return Err(anyhow::anyhow!(
 747→                "Unknown provider '{provider}'. Supported: openai"
 748→            ));
 749→        }
 750→    }
 751→
 752→    // Set the provider as the new default after successful login.
 753→    let mut file_config = config::load_config(data_dir);
 754→    file_config.set_key("provider", canonical).ok();
 755→    config::save_config(data_dir, &file_config)?;
 756→    eprintln!("Default provider set to '{canonical}'");
 757→
 758→    Ok(())
 759→}
