 813→fn run_logout(provider: &str, data_dir: &Path) -> anyhow::Result<()> {
 814→    // Normalize provider name for credential lookup.
 815→    let normalized = match provider {
 816→        "codex" | "openai-codex" => "openai",
 817→        other => other,
 818→    };
 819→    arcan_provider::oauth::remove_tokens(normalized).map_err(|e| anyhow::anyhow!("{e}"))?;
