 821→    // Clear the default provider if it matches the one being logged out.
 822→    let mut file_config = config::load_config(data_dir);
 823→    if file_config.defaults.provider.as_deref() == Some(normalized) {
 824→        file_config.defaults.provider = None;
 825→        config::save_config(data_dir, &file_config)?;
 826→        eprintln!("Default provider cleared");
 827→    }
 828→
 829→    eprintln!("Logged out of {provider}");
 830→    Ok(())
 831→}
