 833→fn main() -> anyhow::Result<()> {
 834→    let cli = Cli::parse();
 835→    let data_dir = resolve_data_dir(&cli.data_dir)?;
 836→
 837→    // Load layered config.
 838→    let file_config = config::load_config(&data_dir);
 839→
 840→    match cli.command {
 841→        Some(Command::Serve {
 842→            max_iterations,
 843→            approval_timeout,
 844→        }) => {
 845→            // Structured logging to stderr for daemon mode
 846→            tracing_subscriber::fmt()
 847→                .with_env_filter(EnvFilter::from_default_env())
 848→                .init();
 849→
 850→            let resolved = config::resolve(
 851→                &file_config,
 852→                cli.provider.as_deref(),
 853→                cli.model.as_deref(),
 854→                cli.port,
 855→                max_iterations,
 856→                approval_timeout,
 857→                cli.autonomic_url.as_deref(),
 858→                cli.spaces_backend.as_deref(),
 859→                cli.spaces_token.as_deref(),
 860→            );
 861→
 862→            run_serve(&data_dir, &resolved, cli.console_dir)
 863→        }
 864→        Some(Command::Chat { session, url }) => {
 865→            // File-based logging for TUI mode (don't clobber the terminal)
 866→            let log_dir = data_dir.join("logs");
 867→            std::fs::create_dir_all(&log_dir)?;
 868→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
 869→            tracing_subscriber::fmt()
 870→                .with_writer(file_appender)
 871→                .with_env_filter(EnvFilter::from_default_env())
 872→                .init();
 873→
 874→            let resolved = config::resolve(
 875→                &file_config,
 876→                cli.provider.as_deref(),
 877→                cli.model.as_deref(),
 878→                cli.port,
 879→                None,
 880→                None,
 881→                cli.autonomic_url.as_deref(),
 882→                cli.spaces_backend.as_deref(),
 883→                cli.spaces_token.as_deref(),
 884→            );
 885→
 886→            let runtime = tokio::runtime::Builder::new_multi_thread()
 887→                .enable_all()
 888→                .build()?;
 889→            runtime.block_on(run_chat(data_dir, &resolved, session, url))
 890→        }
 891→        Some(Command::Login { provider, device }) => run_login(&provider, device, &data_dir),
 892→        Some(Command::Logout { provider }) => run_logout(&provider, &data_dir),
 893→        Some(Command::Api { url, output }) => {
 894→            let resolved = config::resolve(
 895→                &file_config,
 896→                cli.provider.as_deref(),
 897→                cli.model.as_deref(),
 898→                cli.port,
 899→                None,
 900→                None,
 901→                cli.autonomic_url.as_deref(),
 902→                cli.spaces_backend.as_deref(),
 903→                cli.spaces_token.as_deref(),
 904→            );
 905→
 906→            let runtime = tokio::runtime::Builder::new_multi_thread()
 907→                .enable_all()
 908→                .build()?;
