}

/// Session manifest returned on creation.
#[derive(ToSchema)]
#[schema(as = SessionManifest)]
#[allow(dead_code)]
struct SessionManifestSchema {
    session_id: String,
    owner: String,
    created_at: chrono::DateTime<chrono::Utc>,
    workspace_root: String,
    #[schema(schema_with = ModelRoutingSchema::schema)]
