/// Information about a branch within a session.
#[derive(ToSchema)]
#[schema(as = BranchInfo)]
#[allow(dead_code)]
struct BranchInfoSchema {
    branch_id: String,
    parent_branch: Option<String>,
    fork_sequence: u64,
    head_sequence: u64,
