#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum StreamFormat {
    Canonical,
    VercelAiSdkV6,
}

impl StreamFormat {
    fn from_query(value: Option<&str>) -> Self {
        match value {
            Some("vercel_ai_sdk_v6" | "aisdk_v6") => Self::VercelAiSdkV6,
            _ => Self::Canonical,
        }
    }
}

